head.b:skin:
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

body {
    font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
    background: #f0f4f8;
    height: 100dvh;
    display: flex;
    align-items: center;
    justify-content: center;
}

#ai-agent-container {
    width: 100%;
    max-width: 820px;
    background: #ffffff;
    border-radius: 16px;
    box-shadow: 0 12px 40px rgba(0,0,0,0.12);
    display: flex;
    flex-direction: column;
    height: 90dvh;
    overflow: hidden;
}

/* Header */
.agent-header {
    background: linear-gradient(135deg, #1a73e8 0%, #0d5dbf 100%);
    color: white;
    padding: 16px 20px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-shrink: 0;
    gap: 12px;
}
.header-left h2 { font-size: clamp(15px, 4vw, 19px); font-weight: 700; line-height: 1.2; }
.header-left small { font-size: clamp(10px, 2.8vw, 12px); opacity: 0.85; }
.header-right { display: flex; align-items: center; gap: 8px; flex-shrink: 0; }

.status-pill {
    background: #34a853;
    font-size: 11px; font-weight: 600;
    padding: 4px 10px; border-radius: 20px;
    white-space: nowrap;
}
.clear-btn {
    background: rgba(255,255,255,0.2);
    border: none; color: white;
    font-size: 11px; font-weight: 600;
    padding: 4px 10px; border-radius: 20px;
    cursor: pointer; transition: background 0.2s;
}
.clear-btn:hover { background: rgba(255,255,255,0.35); }

/* Chat */
#chat-window {
    flex: 1;
    padding: 16px;
    overflow-y: auto;
    display: flex;
    flex-direction: column;
    gap: 12px;
    -webkit-overflow-scrolling: touch;
    scroll-behavior: smooth;
}

.msg {
    max-width: 82%;
    padding: 10px 14px;
    border-radius: 18px;
    font-size: clamp(13px, 3.5vw, 15px);
    line-height: 1.55;
    word-break: break-word;
}
.msg.user  { align-self: flex-end;   background: #dbeafe; color: #1e40af; border-bottom-right-radius: 4px; }
.msg.bot   { align-self: flex-start; background: #f1f3f4; color: #3c4043; border-bottom-left-radius: 4px; }
.msg.error { align-self: flex-start; background: #fce8e6; color: #c5221f; border-bottom-left-radius: 4px; }
.msg.system {
    align-self: center; font-size: 10px; color: #9aa0a6;
    text-transform: uppercase; letter-spacing: 0.06em;
    background: none; padding: 4px 0;
}

/* Zapier badge — only shows on real integration calls */
.zapier-badge {
    display: inline-block;
    margin-top: 6px;
    font-size: 10px; font-weight: 700;
    color: #1a73e8;
    letter-spacing: 0.03em;
}
.turn-info { display: block; margin-top: 3px; font-size: 9px; color: #bdc1c6; }

/* Typing dots */
.typing-dots span {
    display: inline-block; width: 7px; height: 7px;
    background: #9aa0a6; border-radius: 50%; margin: 0 2px;
    animation: bounce 1.2s infinite;
}
.typing-dots span:nth-child(2) { animation-delay: 0.2s; }
.typing-dots span:nth-child(3) { animation-delay: 0.4s; }
@keyframes bounce {
    0%, 60%, 100% { transform: translateY(0); }
    30% { transform: translateY(-6px); }
}

/* Input */
.input-area {
    border-top: 1px solid #e8eaed;
    padding: 12px 14px;
    display: flex; gap: 8px;
    flex-shrink: 0; align-items: flex-end;
    background: #fff;
}
#user-input {
    flex: 1; border: 1.5px solid #dadce0;
    padding: 10px 14px; border-radius: 24px;
    outline: none; font-size: clamp(13px, 3.5vw, 15px);
    font-family: inherit; resize: none;
    max-height: 110px; line-height: 1.4;
    transition: border-color 0.2s; -webkit-appearance: none;
}
#user-input:focus { border-color: #1a73e8; }
#send-btn {
    background: #1a73e8; color: white; border: none;
    width: 44px; height: 44px; border-radius: 50%;
    cursor: pointer; font-size: 20px;
    display: flex; align-items: center; justify-content: center;
    flex-shrink: 0;
    transition: background 0.2s, transform 0.1s;
    -webkit-tap-highlight-color: transparent;
}
#send-btn:hover  { background: #1557b0; }
#send-btn:active { transform: scale(0.92); }
#send-btn:disabled { background: #bdc1c6; cursor: not-allowed; }

/* Mobile */
@media (max-width: 600px) {
    body { align-items: flex-end; background: #fff; }
    #ai-agent-container { border-radius: 0; height: 100dvh; box-shadow: none; }
    .agent-header { padding: 12px 14px; }
    #chat-window { padding: 12px 10px; gap: 10px; }
    .msg { max-width: 92%; }
    .input-area { padding: 8px 10px 10px; }
}
/* Tablet */
@media (min-width: 601px) and (max-width: 900px) {
    #ai-agent-container { margin: 16px; height: calc(100dvh - 32px); }
}

body.script:
//

const PROXY_ENDPOINT = "https://zap-ai-1zcd.vercel.app/api/agent";
let chatHistory = JSON.parse(localStorage.getItem('agent_chat_history')) || [];

function appendMessage(text, type, id = null, tool = null) {
    const chatWindow = document.getElementById('chat-window');
    if (!chatWindow) return;

    const msgDiv = document.createElement('div');
    msgDiv.className = `msg ${type}`;
    if (id) msgDiv.id = id;

    let content = text;
    if (tool) {
        content += `<span class='tool-tag' style='display:block; font-size:10px; color:#1a73e8; margin-top:5px; font-weight:bold;'>Used Tool: ${tool}</span>`;
    }

    msgDiv.innerHTML = content;
    chatWindow.appendChild(msgDiv);
    chatWindow.scrollTop = chatWindow.scrollHeight;
}

// Load History immediately
chatHistory.forEach(msg => {
    if (msg.role === 'user') {
        appendMessage(msg.content, 'user');
    } else if (msg.role === 'assistant' && msg.content) {
        appendMessage(msg.content, 'bot');
    }
});

async function sendMessage() {
    const inputField = document.getElementById('user-input');
    const query = inputField.value.trim();
    if (!query) return;

    appendMessage(query, 'user');
    inputField.value = '';

    chatHistory.push({ role: "user", content: query });

    const thinkingId = 'think-' + Date.now();
    appendMessage("AI is thinking...", 'bot', thinkingId);

    try {
        const response = await fetch(PROXY_ENDPOINT, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ messages: chatHistory })
        });

        const data = await response.json();

        if (data.newMessage) {
            chatHistory.push(data.newMessage);
            localStorage.setItem('agent_chat_history', JSON.stringify(chatHistory));
        }

        const thinkingElement = document.getElementById(thinkingId);
        if (thinkingElement) thinkingElement.remove();

        appendMessage(data.output, 'bot', null, data.toolUsed);

    } catch (error) {
        const thinkingElement = document.getElementById(thinkingId);
        if (thinkingElement) thinkingElement.innerText = "Error: Connection lost. Check Vercel logs.";
    }
}

// 4. RESET FUNCTION
function resetMemory() {
    // 1. Delete the memory from the browser
    localStorage.removeItem('agent_chat_history');

    // 2. Clear the active array
    chatHistory = [];

    // 3. Reload the page to bring back the default welcome message cleanly
    location.reload();
}

// Enter Button Fix - Bypassing DOMContentLoaded for immediate attachment
const inputField = document.getElementById('user-input');
if (inputField) {
    inputField.addEventListener('keydown', function (e) {
        if ((e.key === 'Enter' || e.keyCode === 13) && !e.shiftKey) {
            e.preventDefault(); 
            sendMessage();
        }
    });
} else {
    console.error("Could not find the user-input box. Check your HTML IDs.");
}

//
